        attrHtml += <code class="rounded-sm bg-(--theme-user-msg-text)/10 dark:bg-(--theme-user-msg-text)/15 px-1 py-0.5 text-(--theme-user-msg-text) text-sm [overflow-wrap:anywhere]">&lt;/div&gt;</code>;
